// Transform roles: add stripped-domain users alongside originals
const roles = $input.all().map(item => item.json);
const results = [];

function stripEmailDomain(username) {
  return username.replace(/@ssi\.com\.vn$/, '');
}

for (const role of roles) {
  const roleName = role.name || '';
  if (!roleName) continue;

  const originalUsers = role.users || [];
  const existingNames = new Set(originalUsers.map(u => u.name || ''));

  const newUsers = [...originalUsers];
  for (const u of originalUsers) {
    const stripped = stripEmailDomain(u.name || '');
    if (stripped !== (u.name || '') && !existingNames.has(stripped)) {
      newUsers.push({ name: stripped, isAdmin: u.isAdmin || false });
      existingNames.add(stripped);
    }
  }

  if (newUsers.length === originalUsers.length) {
    // No new users to add, skip
    continue;
  }

  results.push({
    json: {
      ...role,
      users: newUsers,
      _roleId: role.id,
      _roleName: roleName
    }
  });
}

if (results.length === 0) {
  results.push({ json: { _noRolesToUpdate: true } });
}

return results;

// Main transformation logic
const trinoPolicies = $('Fetch Trino Policies').all().map(i => i.json);
const starrocksPolicies = $('Fetch StarRocks Policies').all().map(i => i.json);
const config = $('Config').first().json;

// Build index of existing StarRocks policies by name
const existingPolicies = {};
for (const p of starrocksPolicies) {
  existingPolicies[p.name] = p;
}

// Helper functions
function stripEmailDomain(username) {
  return username.replace(/@ssi\.com\.vn$/, '');
}

function transformUsers(users) {
  return users.map(u => stripEmailDomain(u));
}

function hasIcebergCatalog(resources) {
  const catalogRes = resources.catalog || {};
  return (catalogRes.values || []).some(v => v.toLowerCase() === 'iceberg');
}

function isIcebergPolicy(policy) {
  // Check primary resources
  if (hasIcebergCatalog(policy.resources || {})) return true;
  // Check additionalResources
  for (const additional of (policy.additionalResources || [])) {
    if (hasIcebergCatalog(additional)) return true;
  }
  return false;
}

function hasCatalogResource(policy) {
  return 'catalog' in (policy.resources || {});
}

function needsUsagePermission(resources) {
  const keys = new Set(Object.keys(resources));
  const catalogOnly = keys.size === 1 && keys.has('catalog');
  const catalogSchema = keys.size === 2 && keys.has('catalog') && keys.has('schema');
  const catalogDatabase = keys.size === 2 && keys.has('catalog') && keys.has('database');
  return catalogOnly || catalogSchema || catalogDatabase;
}

function mapResources(resources) {
  const RESOURCE_MAP = { schema: 'database' };
  const mapped = {};
  for (const [key, value] of Object.entries(resources)) {
    const newKey = RESOURCE_MAP[key] || key;
    mapped[newKey] = value;
  }
  return mapped;
}

function createBasePolicy(sourcePolicy) {
  const name = `sync-trino: ${sourcePolicy.name}`;
  const base = {
    service: config.starrrocksService,
    name: name,
    policyType: sourcePolicy.policyType || 0,
    isEnabled: sourcePolicy.isEnabled !== undefined ? sourcePolicy.isEnabled : true,
    isAuditEnabled: sourcePolicy.isAuditEnabled !== undefined ? sourcePolicy.isAuditEnabled : true,
    resources: mapResources(sourcePolicy.resources || {}),
    description: `Synced from Trino policy: ${sourcePolicy.name} (id=${sourcePolicy.id})`,
  };
  // Map additionalResources if present
  const additional = sourcePolicy.additionalResources || [];
  if (additional.length > 0) {
    base.additionalResources = additional.map(res => mapResources(res));
  }
  return base;
}

function transformAccessPolicy(policy) {
  const newPolicy = createBasePolicy(policy);
  const addUsage = needsUsagePermission(policy.resources || {});
  const newItems = [];

  for (const item of (policy.policyItems || [])) {
    const selectAccesses = (item.accesses || []).filter(a => a.type === 'select');
    const useAccesses = (item.accesses || []).filter(a => a.type === 'use');
    if (!selectAccesses.length && !useAccesses.length) continue;

    const accesses = [];
    if (selectAccesses.length) accesses.push({ type: 'select', isAllowed: true });
    if (addUsage) accesses.push({ type: 'usage', isAllowed: true });

    newItems.push({
      accesses,
      users: transformUsers(item.users || []),
      groups: item.groups || [],
      roles: item.roles || [],
      conditions: item.conditions || [],
      delegateAdmin: item.delegateAdmin || false,
    });
  }

  if (!newItems.length) return null;
  newPolicy.policyItems = newItems;
  return newPolicy;
}

function transformMaskingPolicy(policy) {
  const newPolicy = createBasePolicy(policy);
  newPolicy.dataMaskPolicyItems = (policy.dataMaskPolicyItems || []).map(item => ({
    accesses: item.accesses || [],
    users: transformUsers(item.users || []),
    groups: item.groups || [],
    roles: item.roles || [],
    conditions: item.conditions || [],
    delegateAdmin: item.delegateAdmin || false,
    dataMaskInfo: item.dataMaskInfo || {},
  }));
  return newPolicy;
}

function transformRowFilterPolicy(policy) {
  const newPolicy = createBasePolicy(policy);
  newPolicy.rowFilterPolicyItems = (policy.rowFilterPolicyItems || []).map(item => ({
    accesses: item.accesses || [],
    users: transformUsers(item.users || []),
    groups: item.groups || [],
    roles: item.roles || [],
    conditions: item.conditions || [],
    delegateAdmin: item.delegateAdmin || false,
    rowFilterInfo: item.rowFilterInfo || {},
  }));
  return newPolicy;
}

// Filter iceberg policies
const icebergPolicies = trinoPolicies.filter(p => hasCatalogResource(p) && isIcebergPolicy(p));

const results = [];
let skipped = 0;

for (const policy of icebergPolicies) {
  const policyType = policy.policyType || 0;
  let transformed;

  if (policyType === 0) {
    transformed = transformAccessPolicy(policy);
    if (!transformed) { skipped++; continue; }
  } else if (policyType === 1) {
    transformed = transformMaskingPolicy(policy);
  } else if (policyType === 2) {
    transformed = transformRowFilterPolicy(policy);
  } else {
    skipped++;
    continue;
  }

  const srName = transformed.name;
  let action = 'create';
  let existingId = null;

  if (existingPolicies[srName]) {
    action = 'update';
    existingId = existingPolicies[srName].id;
    transformed.id = existingId;
  }

  results.push({
    json: {
      _action: action,
      _existingId: existingId,
      _policyType: policyType,
      _originalName: policy.name,
      _transformedName: srName,
      policy: transformed,
    }
  });
}

if (results.length === 0) {
  return [{ json: { _noPolicies: true, _skipped: skipped, _total: icebergPolicies.length } }];
}

return results;
